prompt:
dynamically for all catagories and cases: Generate one case as example, the improvement should apply for global development of all catagories and cases, not just for one case or catagory. 

Inputs:
topic: {{topic}}
language: {{language}}
region: {{region}}
patient_constraints: {
  age_range: {{age_range}},
  sex: {{sex}},
  geography_of_living: {{geography}}
}
onset_minutes_ago: {{minutes_from_onset}}
must_include: [
  "medication_list_with_allergies",
  "hemodynamic_profile_warm_cold_wet_dry",
  "test_kinetics_if_applicable",
  "imaging_timing_and_escalation",
  "accepted_vs_rejected_differentials_with_arguments",
  "region_aware_guidelines_and_timing",
  "disposition_plus_followup_and_social_needs"
]

Output format must follow the JSON schema below.


{
  "type": "object",
  "required": ["meta","history","exam","paraclinical","differentials","red_flags","final_diagnosis","pathophysiology","etiology","management","disposition","evidence","teaching","panel_notes"],
  "properties": {
    "meta": {
      "type":"object",
      "required":["topic","language","region","demographics","geography_of_living"],
      "properties":{
        "topic":{"type":"string"},
        "language":{"type":"string"},
        "region":{"type":"string"},
        "demographics":{"type":"object","required":["age","sex"],"properties":{"age":{"type":"integer"},"sex":{"type":"string"}}},
        "geography_of_living":{"type":"string"}
      }
    },
    "history":{
      "type":"object",
      "required":["presenting_complaint","onset_duration_severity","context_triggers","post_event","past_medical_history","medications_current","allergies"],
      "properties":{
        "presenting_complaint":{"type":"string"},
        "onset_duration_severity":{"type":"string"},
        "context_triggers":{"type":"string"},
        "post_event":{"type":"string"},
        "past_medical_history":{"type":"array","items":{"type":"string"}},
        "medications_current":{"type":"array","items":{"type":"string"}},
        "allergies":{"type":"array","items":{"type":"string"}}
      }
    },
    "exam":{
      "type":"object",
      "required":["vitals","orthostatics","general","cardiorespiratory","hemodynamic_profile","pain_distress"],
      "properties":{
        "vitals":{"type":"object"},
        "orthostatics":{"type":"object"},
        "general":{"type":"string"},
        "cardiorespiratory":{"type":"string"},
        "hemodynamic_profile":{"type":"string"},
        "pain_distress":{"type":"string"}
      }
    },
    "paraclinical":{
      "type":"object",
      "required":["labs","ecg","imaging","other_tests","test_kinetics"],
      "properties":{
        "labs":{"type":"array","items":{"type":"string"}},
        "ecg":{"type":"string"},
        "imaging":{"type":"array","items":{"type":"object","required":["modality","timing","rationale"],"properties":{"modality":{"type":"string"},"timing":{"type":"string"},"rationale":{"type":"string"}}}},
        "other_tests":{"type":"array","items":{"type":"string"}},
        "test_kinetics":{"type":"array","items":{"type":"object","required":["test","timing_relation","notes"],"properties":{"test":{"type":"string"},"timing_relation":{"type":"string"},"notes":{"type":"string"}}}}
      }
    },
    "differentials":{
      "type":"array",
      "items":{"type":"object","required":["name","status","why_for","why_against"],"properties":{
        "name":{"type":"string"},
        "status":{"type":"string"},
        "why_for":{"type":"string"},
        "why_against":{"type":"string"}
      }}
    },
    "red_flags":{"type":"array","items":{"type":"string"}},
    "final_diagnosis":{"type":"object","required":["name","rationale"],"properties":{"name":{"type":"string"},"rationale":{"type":"string"}}},
    "pathophysiology":{"type":"object","required":["mechanism","systems_organs"],"properties":{"mechanism":{"type":"string"},"systems_organs":{"type":"string"}}},
    "etiology":{"type":"object","required":["underlying_cause"],"properties":{"underlying_cause":{"type":"string"}}},
    "management":{
      "type":"object",
      "required":["immediate","escalation_if_wrong_dx","region_guidelines","timing_windows"],
      "properties":{
        "immediate":{"type":"array","items":{"type":"string"}},
        "escalation_if_wrong_dx":{"type":"array","items":{"type":"string"}},
        "region_guidelines":{"type":"array","items":{"type":"object","required":["society","year","applies_to","note"],"properties":{"society":{"type":"string"},"year":{"type":"string"},"applies_to":{"type":"string"},"note":{"type":"string"}}}},
        "timing_windows":{"type":"array","items":{"type":"object","required":["action","window"],"properties":{"action":{"type":"string"},"window":{"type":"string"}}}}
      }
    },
    "disposition":{
      "type":"object",
      "required":["admit_vs_discharge","unit","follow_up","social_needs"],
      "properties":{
        "admit_vs_discharge":{"type":"string"},
        "unit":{"type":"string"},
        "follow_up":{"type":"string"},
        "social_needs":{"type":"string"}
      }
    },
    "evidence":{
      "type":"object",
      "required":["prevalence","incidence","key_tests","prognosis"],
      "properties":{
        "prevalence":{"type":"string"},
        "incidence":{"type":"string"},
        "key_tests":{"type":"array","items":{"type":"object","required":["test","sensitivity","specificity","notes"],"properties":{"test":{"type":"string"},"sensitivity":{"type":"string"},"specificity":{"type":"string"},"notes":{"type":"string"}}}},
        "prognosis":{"type":"string"}
      }
    },
    "teaching":{
      "type":"object",
      "required":["pearls","mnemonics"],
      "properties":{
        "pearls":{"type":"array","items":{"type":"string"}},
        "mnemonics":{"type":"array","items":{"type":"string"}}
      }
    },
    "panel_notes":{
      "type":"object",
      "required":["internal_medicine","surgery","emergency_medicine"],
      "properties":{
        "internal_medicine":{"type":"string"},
        "surgery":{"type":"string"},
        "emergency_medicine":{"type":"string"}
      }
    }
  }
}]
